import Foundation

/**
 * Manual Swift bridge for OpenGrid (Diplomat-style)
 * Wraps the C functions generated by Diplomat
 */

public class OpenGridEngine {
    private var ptr: OpaquePointer?

    public init() {
        self.ptr = OpenGridEngine_new()
    }

    public func createNode(name: String) -> NodeHandle? {
        guard let enginePtr = self.ptr else { return nil }
        
        // Convert Swift String to DiplomatStringView (simulated for now)
        // In actual impl, you'd use the Diplomat helpers to pass the string
        let nodePtr = OpenGridEngine_create_node(enginePtr, name.asDiplomatStringView())
        return NodeHandle(ptr: nodePtr)
    }

    deinit {
        if let ptr = self.ptr {
            OpenGridEngine_destroy(ptr)
        }
    }
}

public class NodeHandle {
    private var ptr: OpaquePointer?

    internal init(ptr: OpaquePointer?) {
        self.ptr = ptr
    }

    public static func newEphemeral() -> NodeHandle {
        return NodeHandle(ptr: NodeHandle_new_ephemeral())
    }

    public func submitEvent(payload: Data) -> UInt64 {
        guard let nodePtr = self.ptr else { return 0 }
        
        // Convert Data to DiplomatU8View
        return payload.withUnsafeBytes { buf in
            let view = DiplomatU8View(data: buf.baseAddress?.assumingMemoryBound(to: UInt8.self), len: buf.count)
            return NodeHandle_submit_event(nodePtr, view)
        }
    }

    public func currentVersion() -> UInt64 {
        guard let nodePtr = self.ptr else { return 0 }
        return NodeHandle_current_version(nodePtr)
    }

    deinit {
        if let ptr = self.ptr {
            NodeHandle_destroy(ptr)
        }
    }
}

// Helper extension for String to DiplomatStringView conversion
extension String {
    func asDiplomatStringView() -> DiplomatStringView {
        return self.withCString { ptr in
            DiplomatStringView(data: ptr, len: self.utf8.count)
        }
    }
}
